import { useEffect } from "react";
import { useVisitTracker, logVisit } from "@/hooks/useVisitTracker";
import { useAuth } from "@/contexts/AuthContext";

/**
 * Mounts global visit + error tracking.
 * - Logs every route change (success)
 * - Captures uncaught JS errors and unhandled promise rejections
 */
export const VisitTracker = () => {
  useVisitTracker();
  const { user } = useAuth();

  useEffect(() => {
    const onError = (e: ErrorEvent) => {
      logVisit(
        {
          path: window.location.pathname,
          search: window.location.search || undefined,
          status: "error",
          error_message: `${e.message} @ ${e.filename}:${e.lineno}:${e.colno}`,
        },
        { id: user?.id, email: user?.email }
      );
    };

    const onRejection = (e: PromiseRejectionEvent) => {
      const reason = e.reason;
      const msg =
        typeof reason === "string"
          ? reason
          : reason?.message || JSON.stringify(reason)?.slice(0, 500) || "unknown rejection";
      logVisit(
        {
          path: window.location.pathname,
          search: window.location.search || undefined,
          status: "error",
          error_message: `[unhandledrejection] ${msg}`,
        },
        { id: user?.id, email: user?.email }
      );
    };

    window.addEventListener("error", onError);
    window.addEventListener("unhandledrejection", onRejection);
    return () => {
      window.removeEventListener("error", onError);
      window.removeEventListener("unhandledrejection", onRejection);
    };
  }, [user?.id, user?.email]);

  return null;
};

export default VisitTracker;
